func todosFilterClass(self, cur string) string {
	if self == cur {
		return "filter active"
	}
	return "filter"
}

func todosFilterHref(slug, status, category string) string {
	out := "/c/" + slug + "/todos?status=" + status
	if category != "" {
		out += "&category=" + queryEscape(category)
	}
	return out
}

func todoStatusLabel(s string) string {
	switch s {
	case "open":
		return "Open"
	case "doing":
		return "Doing"
	case "done":
		return "Done"
	}
	return s
}

func todoBacklinkHref(slug string, t TodoRow) string {
	switch t.SourceKind {
	case "chat":
		return "/c/" + slug + "/history?d=" + t.SourceDay + "#msg-" + t.SourceID
	case "forum_post":
		return "/c/" + slug + "/forum/" + t.SourceThreadID + "#post-" + t.SourceID
	}
	return "#"
}

func todoBacklinkLabel(t TodoRow) string {
	switch t.SourceKind {
	case "chat":
		return "open in history"
	case "forum_post":
		return "open in thread"
	}
	return "open"
}

